firmware_template.source:
#include "ads1015.h"
#include <Wire.h>
#include <Adafruit_ADS1X15.h>
static Adafruit_ADS1015 a;
void ads1015_setup(){Wire.begin();a.begin(0x48);a.setGain(GAIN_TWOTHIRDS);Serial.println("[ads1015] OK");}
int16_t ads1015_read(uint8_t c){return a.readADC_SingleEnded(c);}
float ads1015_read_volts(uint8_t c){return a.computeVolts(a.readADC_SingleEnded(c));}
